mapper.select:
select count(1) as project_count, ifnull(sum(ifnull(p.total_budget, 0)), 0) as total_budget, ifnull(sum(ifnull(p.actual_cost, 0)), 0) as actual_cost, ifnull(sum(ifnull(p.budget_balance, ifnull(p.total_budget, 0) - ifnull(p.actual_cost, 0))), 0) as budget_balance, ifnull(sum(ifnull(p.contract_amount, 0)), 0) as contract_amount, ifnull(sum(ifnull(p.contract_amount, 0) - ifnull(p.total_budget, 0)), 0) as profit_margin, ( select ifnull(sum(c.amount), 0) from cost_posting_record c inner join proj_info p2 on p2.proj_id = c.proj_id and p2.del_flag = '0' where date_format(coalesce(c.post_time, c.create_time), '%Y-%m') = date_format(curdate(), '%Y-%m')
and p2.status in #{status}
) as month_posting_amount, ( select ifnull(sum(c.amount), 0) from cost_posting_record c inner join proj_info p2 on p2.proj_id = c.proj_id and p2.del_flag = '0' where date_format(coalesce(c.post_time, c.create_time), '%Y-%m') = date_format(date_sub(curdate(), interval 1 month), '%Y-%m')
and p2.status in #{status}
) as last_month_posting_amount from proj_info p where p.del_flag = '0'
and p.status in #{status}
